function [Isig,dt,l0,dl] = plotfrog_bp(P,G,T,l0,varargin)% PLOTFROG plots a FROG trace.error(nargchk(4,6,nargin));[sve,u] = ParseVarargin_bp(varargin, false, 'nm/fs');dt = abs(mean(diff(T)));Esig = CalcEsig_bp(P,G);Isig = abs(fft_FROG_bp(Esig)).^2;dw = 2*pi ./ (max(T) - min(T));l0 = l0 / 2;w0 = ltow(l0);W = (((0:length(T)-1) - (length(T) / 2)) * dw + w0)';[L,Isig] = ToConstWaveSpc_bp(W,Isig);Isig = nonegatives_bp(Isig);dl = mean(diff(L));plot_Isig_bp(Isig,L,T);if sve    FrogSave_bp(Isig,dt,l0,dl);end